let ai_resource_identifier_of_yojson = string_of_yojson

let ai_benchmark_inference_component_of_yojson tree path =
  let _list = assoc_of_yojson tree path in
  ({ identifier = value_for_key ai_resource_identifier_of_yojson "Identifier" _list path }
    : ai_benchmark_inference_component)

let ai_benchmark_inference_component_list_of_yojson tree path =
  list_of_yojson ai_benchmark_inference_component_of_yojson tree path

let string__of_yojson = string_of_yojson

let ai_benchmark_endpoint_of_yojson tree path =
  let _list = assoc_of_yojson tree path in
  ({
     identifier = value_for_key ai_resource_identifier_of_yojson "Identifier" _list path;
     target_container_hostname =
       option_of_yojson (value_for_key string__of_yojson "TargetContainerHostname") _list path;
     inference_components =
       option_of_yojson
         (value_for_key ai_benchmark_inference_component_list_of_yojson "InferenceComponents")
         _list path;
   }
    : ai_benchmark_endpoint)

let ai_benchmark_job_arn_of_yojson = string_of_yojson

let ai_benchmark_job_status_of_yojson (tree : t) path =
  ((match tree with
    | `String "InProgress" -> IN_PROGRESS
    | `String "Completed" -> COMPLETED
    | `String "Failed" -> FAILED
    | `String "Stopping" -> STOPPING
    | `String "Stopped" -> STOPPED
    | `String value ->
        raise (deserialize_unknown_enum_value_error path "AIBenchmarkJobStatus" value)
    | _ -> raise (deserialize_wrong_type_error path "AIBenchmarkJobStatus")
     : ai_benchmark_job_status)
    : ai_benchmark_job_status)

