let ai_benchmark_target_of_yojson (tree : t) path =
  let _list = assoc_of_yojson tree path in
  let key, value_ =
    match _list with
    | (key, value_) :: _ -> (key, value_)
    | _ -> raise (deserialize_wrong_type_error path "union")
  in
  (match key with
   | "Endpoint" -> Endpoint (ai_benchmark_endpoint_of_yojson value_ path)
   | _ as unknown -> raise (deserialize_unknown_enum_value_error path "AIBenchmarkTarget" unknown)
    : ai_benchmark_target)

