let framework_of_yojson (tree : t) path =
  ((match tree with
    | `String "TENSORFLOW" -> TENSORFLOW
    | `String "KERAS" -> KERAS
    | `String "MXNET" -> MXNET
    | `String "ONNX" -> ONNX
    | `String "PYTORCH" -> PYTORCH
