let recommendation_status_of_yojson (tree : t) path =
  ((match tree with
    | `String "IN_PROGRESS" -> IN_PROGRESS
    | `String "COMPLETED" -> COMPLETED
    | `String "FAILED" -> FAILED
    | `String "NOT_APPLICABLE" -> NOT_APPLICABLE
    | `String value ->
        raise (deserialize_unknown_enum_value_error path "RecommendationStatus" value)
    | _ -> raise (deserialize_wrong_type_error path "RecommendationStatus")
     : recommendation_status)
    : recommendation_status)

