let stage_status_of_yojson (tree : t) path =
  ((match tree with
    | `String "CREATING" -> Creating
    | `String "READYTODEPLOY" -> ReadyToDeploy
    | `String "STARTING" -> Starting
    | `String "INPROGRESS" -> InProgress
    | `String "DEPLOYED" -> Deployed
    | `String "FAILED" -> Failed
    | `String "STOPPING" -> Stopping
    | `String "STOPPED" -> Stopped
    | `String value -> raise (deserialize_unknown_enum_value_error path "StageStatus" value)
    | _ -> raise (deserialize_wrong_type_error path "StageStatus")
     : stage_status)
    : stage_status)

