  ((match tree with
    | `String "PriorityClasses" -> PRIORITY_CLASSES
    | `String "FairShare" -> FAIR_SHARE
    | `String "IdleResourceSharing" -> IDLE_RESOURCE_SHARING
    | `String value ->
        raise (deserialize_unknown_enum_value_error path "SchedulerConfigComponent" value)
    | _ -> raise (deserialize_wrong_type_error path "SchedulerConfigComponent")
     : scheduler_config_component)
