let variant_property_type_of_yojson (tree : t) path =
  ((match tree with
    | `String "DesiredInstanceCount" -> DesiredInstanceCount
    | `String "DesiredWeight" -> DesiredWeight
    | `String "DataCaptureConfig" -> DataCaptureConfig
    | `String value -> raise (deserialize_unknown_enum_value_error path "VariantPropertyType" value)
    | _ -> raise (deserialize_wrong_type_error path "VariantPropertyType")
     : variant_property_type)
    : variant_property_type)

let variant_property_of_yojson tree path =
  let _list = assoc_of_yojson tree path in
  ({
     variant_property_type =
       value_for_key variant_property_type_of_yojson "VariantPropertyType" _list path;
   }
    : variant_property)

